    """Composer for creating transaction groups for StructMappingTest contract calls"""

    def __init__(self, client: "StructMappingTestClient"):
        self.client = client
        self._composer = client.algorand.new_group()
        self._result_mappers: list[typing.Callable[[algokit_utils.ABIReturn | None], object] | None] = []

